import UIKit
import Alamofire
import SwiftyJSON

class Stock {
    var symbol: String
    var name: String
    var price: Double
    
    init(symbol: String, name: String, price: Double) {
        self.symbol = symbol
        self.name = name
        self.price = price
    }
}

class Portfolio {
    var stocks: [Stock] = []
    
    func add(stock: Stock) {
        stocks.append(stock)
    }
    
    func remove(stock: Stock) {
        if let index = stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            stocks.remove(at: index)
        }
    }
}

class Trade {
    var symbol: String
    var quantity: Int
    
    init(symbol: String, quantity: Int) {
        self.symbol = symbol
        self.quantity = quantity
    }
}

class TradingApp {
    let apiEndpoint = "https://api.example.com/stock"
    
    func executeTrade(trade: Trade, completion: @escaping (Bool) -> Void) {
        AF.request(apiEndpoint + "/\(trade.symbol)", method: .get).responseJSON { response in
            switch response.result {
            case .success(let value):
                let json = JSON(value)
                if let price = json["price"].double {
                    let cost = price * Double(trade.quantity)
                    print("Trade executed for \(trade.symbol) at $\(cost)")
                    completion(true)
                } else {
                    print("Failed to execute trade")
                    completion(false)
                }
            case .failure(let error):
                print("Error executing trade: \(error.localizedDescription)")
                completion(false)
            }
        }
    }
    
    func getPortfolio(completion: @escaping ([Stock]) -> Void) {
        AF.request(apiEndpoint + "/portfolio").responseJSON { response in
            switch response.result {
            case .success(let value):
                let json = JSON(value)
                var stocks: [Stock] = []
                for item in json.arrayValue {
                    if let symbol = item["symbol"].string, let name = item["name"].string, let price = item["price"].double {
                        stocks.append(Stock(symbol: symbol, name: name, price: price))
                    }
                }
                completion(stocks)
            case .failure(let error):
                print("Error fetching portfolio: \(error.localizedDescription)")
                completion([])
            }
        }
    }
}

class ViewController: UIViewController {
    let tradingApp = TradingApp()
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var executeTradeButton: UIButton!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        executeTradeButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
    }
    
    @objc func executeTrade() {
        guard let symbol = stockSymbolTextField.text, let quantityString = quantityTextField.text else { return }
        if let quantity = Int(quantityString) {
            tradingApp.executeTrade(trade: Trade(symbol: symbol, quantity: quantity)) { success in
                print("Trade executed successfully: \(success)")
            }
        } else {
            print("Invalid quantity")
        }
    }
}